# 输入获取
taskA, taskB, num = map(int, input().split(","))


# 算法入口
def getResult(taskA, taskB, num):
    if num == 0:
        return "[]"

    if taskA == taskB:
        return [taskA * num]

    ans = set()
    for i in range(num + 1):
        ans.add(taskA * i + taskB * (num - i))

    return sorted(ans)


# 算法调用
print(getResult(taskA, taskB, num))
